        if (grid[j][j] < grid[0][0]) return grid[j][j];
        return grid[0][0];
    }
    int minSumPath(vector<vector<int>> &grid) {
        int n = grid.size();
        int m = grid[0].size();
        int up = grid[0][0] + grid[0][1] + grid[0][2];
        int left = grid[0][0] + grid[1][0] + grid[2][0];
        return min(left, up);
    }
